func main() {
    // Directed graph from edge list
    edges := [][]int{{0, 1}, {0, 2}, {1, 3}, {2, 3}}
    graph := make(map[int][]int)
    for _, e := range edges {
        graph[e[0]] = append(graph[e[0]], e[1])
    }
    fmt.Println(graph)
    // map[0:[1 2] 1:[3] 2:[3]]

    // Undirected: add both directions
    undirected := make(map[int][]int)
    for _, e := range edges {
        undirected[e[0]] = append(undirected[e[0]], e[1])
        undirected[e[1]] = append(undirected[e[1]], e[0])
    }
    fmt.Println(undirected)
}

