func main() {
    n := 6
    graph := map[int][]int{0: {1}, 1: {0}, 2: {3}, 3: {2}, 4: {5}, 5: {4}}
    visited := map[int]bool{}
    components := 0

    var dfs func(int)
    dfs = func(node int) {
        visited[node] = true
        for _, nb := range graph[node] {
            if !visited[nb] { dfs(nb) }
        }
    }

    for i := 0; i < n; i++ {
        if !visited[i] {
            dfs(i)
            components++
        }
    }
    fmt.Println(components)  // 3
}

